// // This module implements a 4-bit synchronous down/up counter with a clear signal. The counter counts down when up_down is high, and counts up when up_down is low. It clears to 0 when clear is high. The count value should be output as a 4-bit bus (output [3:0] count).
module top_module(
	input clk,
	input up_down,
	input clear,
	output reg [3:0] count);
always @(posedge clk) begin
	if (clear)
		count <= 0;
	else if (up_down)
		count <= count + 1;
	else
		count <= count - 1;
end

endmodule
